const res = $input.first().json;

if (!res || typeof res !== 'object' || !res.rates) {
  return [{
    json: {
      ok: false,
      provider: 'frankfurter',
      error: 'invalid_response'
    }
  }];
}

return [{
  json: {
    ok: true,
    provider: 'frankfurter',
    base: (res.base || '').toUpperCase(),
    asOf: res.date || null,
    rates: res.rates
  }
}];

const res = $input.first().json;

if (!res || res.result !== 'success' || !res.rates) {
  return [{
    json: {
      ok: false,
      provider: 'open.er-api.com',
      error: res?.error_type || 'invalid_response'
    }
  }];
}

return [{
  json: {
    ok: true,
    provider: 'open.er-api.com',
    base: (res.base_code || '').toUpperCase(),
    asOf: res.time_last_update_utc || res.time_last_update_unix || null,
    rates: res.rates
  }
}];

return [{
  json: {
    ok: false,
    provider: 'frankfurter',
    error: 'invalid_basecurrency'
  }
}];

return [{
  json: {
    ok: false,
    provider: 'open.er-api.com',
    error: 'invalid_basecurrency'
  }
}];

// Source of truth: Create List
const req = $('Validate & Normalize Inputs').first().json;

const requestedBase = String(req.baseCurrency).toUpperCase();
const requestedCurrencies = Array.isArray(req.currencies)
  ? req.currencies.map(c => String(c).toUpperCase())
  : [];

// Current FX payload
const fx = $input.first().json.fx || {};
const rates = fx.rates || {};
const sources = fx.sources || {};

// Prepare trimmed objects
const trimmedRates = {};
const trimmedSources = {};

// Always include base
trimmedRates[requestedBase] = 1;
if (sources[requestedBase]) {
  trimmedSources[requestedBase] = sources[requestedBase];
}

// Include only requested currencies
for (const sym of requestedCurrencies) {
  if (typeof rates[sym] === 'number') {
    trimmedRates[sym] = rates[sym];
    if (sources[sym]) {
      trimmedSources[sym] = sources[sym];
    }
  }
}

return [
  {
    json: {
      ...$input.first().json,
      fx: {
        base: requestedBase,
        asOf: fx.asOf || null,
        rates: trimmedRates,
        sources: trimmedSources
      }
    }
  }
];

// Get base currency from trigger
const trim = $input.first().json.trim;
const baseCurrencyRaw = $input.first().json.baseCurrency;
const baseCurrency = baseCurrencyRaw?.toUpperCase();

const currenciesRaw = $input.first().json.currencies;

// Preparing return object
let object = {
  valid: false,
  reason: '',
  trim,
  baseCurrency,
  currencies: currenciesRaw
};

if (!baseCurrency || typeof baseCurrency !== 'string') {
  object.reason = 'baseCurrency is missing or invalid';
} else if (!Array.isArray(currenciesRaw)) {
  object.reason = 'currencies is not an array';
} else {
    // Check presence
  const currencies = currenciesRaw.map(c => c.toUpperCase());
  const hasBase = currencies.includes(baseCurrency);
  const filteredCurrencies = hasBase
    ? currencies.filter((c) => c !== baseCurrency)
    : currencies;
  object.valid = true;
  object.currencies = filteredCurrencies;
}

return [
  {
    json: object
  }
];

const base = $input.first().json.baseCurrency?.toUpperCase();

const staticRates = {};
const staticMeta = {};

// only apply when base is USD
if (base === 'USD') {
  // optional
  // staticRates.AED = 3.6725;
  // staticMeta.AED = 'static_usd_peg';
  // staticRates.SAR = 3.75;
  // staticMeta.SAR = 'static_usd_peg';
  // staticRates.QAR = 3.64;
  // staticMeta.QAR = 'static_usd_peg';
}

return [{
  json: {
    ...$input.first().json,
    fx: {
      base,
      asOf: new Date().toISOString(),
      rates: staticRates,
      sources: staticMeta
    }
  }
}];

function isRate(x) {
  return typeof x === 'number' && Number.isFinite(x) && x > 0;
}

const req = $('Validate & Normalize Inputs').first().json;     // source of truth
const requestedBase = req.baseCurrency;        // already uppercase
const requestedSymbols = req.currencies || []; // already excludes base

const runningFx = $input.first().json.fx || { base: requestedBase, rates: {}, sources: {}, asOf: null };
const rates = runningFx.rates || {};

const missing = [];
const invalid = [];

for (const sym of requestedSymbols) {
  const v = rates[sym];
  if (v == null) missing.push(sym);
  else if (!isRate(v)) invalid.push(sym);
}

return [{
  json: {
    fx: {
      base: requestedBase,
      asOf: runningFx.asOf || new Date().toISOString(),
      rates: rates,
      sources: runningFx.sources || {}
    },
    missing,
    invalid,
    complete: missing.length === 0 && invalid.length === 0
  }
}];

function isRate(x) {
  return typeof x === 'number' && Number.isFinite(x) && x > 0;
}

const requestedBase = $('Validate & Normalize Inputs').first().json.baseCurrency.toUpperCase();
const requestedSymbols = $('Validate & Normalize Inputs').first().json.currencies; // already excludes base

const runningFx = $('Initialize Coverage Tracking').first().json.fx;
const provider = $input.first().json; // normalized provider output

// start with running
const mergedRates = { ...(runningFx.rates || {}) };
const mergedSources = { ...(runningFx.sources || {}) };

// only merge provider if ok and base matches
if (provider.ok && provider.base === requestedBase && provider.rates && typeof provider.rates === 'object') {
  for (const [k, v] of Object.entries(provider.rates)) {
    const sym = k.toUpperCase();
    if (!isRate(v)) continue;

    // do not overwrite existing rate (static wins if already set)
    if (mergedRates[sym] == null) {
      mergedRates[sym] = v;
      mergedSources[sym] = provider.provider;
    }
  }
}

// now check coverage
const missing = [];
const invalid = [];

for (const sym of requestedSymbols) {
  const v = mergedRates[sym];
  if (v == null) missing.push(sym);
  else if (!isRate(v)) invalid.push(sym);
}

const complete = missing.length === 0 && invalid.length === 0;

return [{
  json: {
    fx: {
      base: requestedBase,
      asOf: provider.asOf || runningFx.asOf,
      rates: mergedRates,
      sources: mergedSources
    },
    complete,
    missing,
    invalid
  }
}];

function isRate(x) {
  return typeof x === 'number' && Number.isFinite(x) && x > 0;
}

const requestedBase = $('Validate & Normalize Inputs').first().json.baseCurrency.toUpperCase();
const requestedSymbols = $('Validate & Normalize Inputs').first().json.currencies; // already excludes base

const runningFx = $('Merge Rates & Check Coverage (1)').first().json.fx || { base: requestedBase, rates: {}, sources: {} };
const provider = $input.first().json; // normalized provider output

// start with running
const mergedRates = { ...(runningFx.rates || {}) };
const mergedSources = { ...(runningFx.sources || {}) };

// only merge provider if ok and base matches
if (provider.ok && provider.base === requestedBase && provider.rates && typeof provider.rates === 'object') {
  for (const [k, v] of Object.entries(provider.rates)) {
    const sym = k.toUpperCase();
    if (!isRate(v)) continue;

    // do not overwrite existing rate (static wins if already set)
    if (mergedRates[sym] == null) {
      mergedRates[sym] = v;
      mergedSources[sym] = provider.provider;
    }
  }
}

// now check coverage
const missing = [];
const invalid = [];

for (const sym of requestedSymbols) {
  const v = mergedRates[sym];
  if (v == null) missing.push(sym);
  else if (!isRate(v)) invalid.push(sym);
}

const complete = missing.length === 0 && invalid.length === 0;

return [{
  json: {
    fx: {
      base: requestedBase,
      asOf: provider.asOf || runningFx.asOf,
      rates: mergedRates,
      sources: mergedSources
    },
    complete,
    missing,
    invalid
  }
}];

